-- labs_initialize_db
CREATE TABLE labs_building (
	building_id int4 NOT NULL,
	building_name text,
	CONSTRAINT labs_building_pkey PRIMARY KEY (building_id)
);

CREATE TABLE labs_building_sample_pos (
	id text,
	point_2d geometry,
	point_3d geometry,
	line geometry,
	rectangle geometry,
	polygon geometry,
	floor text,
	hopara_scope text,
    tenantId text,
	hopara_size integer NULL,
    hopara_size_reference_zoom numeric(24,8) NULL,
    hopara_color text NULL,
    hopara_scale integer NULL
);

CREATE INDEX labs_building_sample_pos_id ON labs_building_sample_pos USING btree (id);
CREATE INDEX labs_building_sample_pos_line_spatial ON labs_building_sample_pos USING gist (line);
CREATE INDEX labs_building_sample_pos_point_2d_spatial ON labs_building_sample_pos USING gist (point_2d);
CREATE INDEX labs_building_sample_pos_point_3d_spatial ON labs_building_sample_pos USING gist (point_3d);
CREATE INDEX labs_building_sample_pos_polygon_spatial ON labs_building_sample_pos USING gist (polygon);
CREATE INDEX labs_building_sample_pos_rectangle_spatial ON labs_building_sample_pos USING gist (rectangle);
CREATE INDEX labs_building_sample_pos_hopara_scope ON labs_building_sample_pos USING btree (hopara_scope);

CREATE TABLE labs_floorplans (
	floorplan_id int4 NOT NULL,
	name text,
	building_id int4 ,
	CONSTRAINT labs_floorplans_pkey PRIMARY KEY (floorplan_id)
);

CREATE TABLE labs_floorplans_sample_pos (
	id text,
	point_2d geometry,
	point_3d geometry,
	line geometry,
	rectangle geometry,
	polygon geometry,
	floor text,
	hopara_scope text,
    tenantId text,
	hopara_size integer,
    hopara_size_reference_zoom numeric(24,8),
    hopara_color text,
    hopara_scale integer
);

CREATE INDEX labs_floorplans_sample_pos_id ON labs_floorplans_sample_pos USING btree (id);
CREATE INDEX labs_floorplans_sample_pos_line_spatial ON labs_floorplans_sample_pos USING gist (line);
CREATE INDEX labs_floorplans_sample_pos_point_2d_spatial ON labs_floorplans_sample_pos USING gist (point_2d);
CREATE INDEX labs_floorplans_sample_pos_point_3d_spatial ON labs_floorplans_sample_pos USING gist (point_3d);
CREATE INDEX labs_floorplans_sample_pos_polygon_spatial ON labs_floorplans_sample_pos USING gist (polygon);
CREATE INDEX labs_floorplans_sample_pos_rectangle_spatial ON labs_floorplans_sample_pos USING gist (rectangle);
CREATE INDEX labs_floorplans_sample_pos_hopara_scope ON labs_floorplans_sample_pos USING btree (hopara_scope);

CREATE TABLE labs_assets (
	asset_id varchar(50) NOT NULL,
	name text,
	room text,
	model text,
	type text,
	building_id int4,
	risk_score int4,
	has_model BOOLEAN,
	CONSTRAINT labs_assets_pk PRIMARY KEY (asset_id)
);

CREATE TABLE labs_assets_sample_pos (
	id text,
	point_2d geometry,
	point_3d geometry,
	line geometry,
	rectangle geometry,
	polygon geometry,
	floor text,
	hopara_scope text,
    tenantId text,
	hopara_size integer,
    hopara_size_reference_zoom numeric(24,8),
    hopara_color text,
    hopara_scale integer
);

CREATE INDEX labs_assets_sample_pos_id ON labs_assets_sample_pos USING btree (id);
CREATE INDEX labs_assets_sample_pos_line_spatial ON labs_assets_sample_pos USING gist (line);
CREATE INDEX labs_assets_sample_pos_point_2d_spatial ON labs_assets_sample_pos USING gist (point_2d);
CREATE INDEX labs_assets_sample_pos_point_3d_spatial ON labs_assets_sample_pos USING gist (point_3d);
CREATE INDEX labs_assets_sample_pos_polygon_spatial ON labs_assets_sample_pos USING gist (polygon);
CREATE INDEX labs_assets_sample_pos_rectangle_spatial ON labs_assets_sample_pos USING gist (rectangle);
CREATE INDEX labs_assets_sample_pos_hopara_scope ON labs_assets_sample_pos USING btree (hopara_scope);

CREATE TABLE labs_rooms (
	room_id text NOT NULL,
	name text,
	description text,
	building_id int4,
	CONSTRAINT labs_rooms_pkey PRIMARY KEY (room_id)
);

CREATE TABLE labs_rooms_sample_pos (
	id text,
	point_2d geometry,
	point_3d geometry,
	line geometry,
	rectangle geometry,
	polygon geometry,
	floor text,
	hopara_scope text,
    tenantId text,
	hopara_size integer,
    hopara_size_reference_zoom numeric(24,8),
    hopara_color text,
    hopara_scale integer
);

CREATE INDEX labs_rooms_sample_pos_id ON labs_rooms_sample_pos USING btree (id);
CREATE INDEX labs_rooms_sample_pos_line_spatial ON labs_rooms_sample_pos USING gist (line);
CREATE INDEX labs_rooms_sample_pos_point_2d_spatial ON labs_rooms_sample_pos USING gist (point_2d);
CREATE INDEX labs_rooms_sample_pos_point_3d_spatial ON labs_rooms_sample_pos USING gist (point_3d);
CREATE INDEX labs_rooms_sample_pos_polygon_spatial ON labs_rooms_sample_pos USING gist (polygon);
CREATE INDEX labs_rooms_sample_pos_rectangle_spatial ON labs_rooms_sample_pos USING gist (rectangle);
CREATE INDEX labs_rooms_sample_pos_hopara_scope ON labs_rooms_sample_pos USING btree (hopara_scope);

CREATE TABLE labs_sensors (
	sensor_id text NOT NULL,
	asset_id text,
	room_id text,
	type text,
    PRIMARY KEY(sensor_id),
    FOREIGN KEY(asset_id) REFERENCES labs_assets(asset_id),
    FOREIGN KEY(room_id) REFERENCES labs_rooms(room_id)
);

CREATE TABLE labs_sensors_sample_pos (
	id text,
	point_2d geometry,
	point_3d geometry,
	line geometry,
	rectangle geometry,
	polygon geometry,
	floor text,
	hopara_scope text,
    tenantId text,
	hopara_size integer,
    hopara_size_reference_zoom numeric(24,8),
    hopara_color text,
    hopara_scale integer
);

CREATE INDEX labs_sensors_sample_pos_id ON labs_sensors_sample_pos USING btree (id);
CREATE INDEX labs_sensors_sample_pos_line_spatial ON labs_sensors_sample_pos USING gist (line);
CREATE INDEX labs_sensors_sample_pos_point_2d_spatial ON labs_sensors_sample_pos USING gist (point_2d);
CREATE INDEX llabs_sensors_sample_pos_point_3d_spatial ON labs_sensors_sample_pos USING gist (point_3d);
CREATE INDEX labs_sensors_sample_pos_polygon_spatial ON labs_sensors_sample_pos USING gist (polygon);
CREATE INDEX labs_sensors_sample_pos_rectangle_spatial ON labs_sensors_sample_pos USING gist (rectangle);
CREATE INDEX labs_sensors_sample_pos_hopara_scope ON labs_sensors_sample_pos USING btree (hopara_scope);

CREATE TABLE labs_alerts (
    sensor_id text NOT NULL,
    warning float8,
    critical float8,
    CONSTRAINT labs_alerts_pkey PRIMARY KEY (sensor_id),
    CONSTRAINT labs_alerts_sensor_id_fkey FOREIGN KEY (sensor_id) REFERENCES labs_sensors(sensor_id)
);

CREATE TABLE labs_assets_risk (
	equipment_id text,
	device_type text,
	risk_score int4,
	model text
);


 


	
	


	



